export function AgendaGroupedContent({
  filteredLength,
  groupMode,
  groupedByAnimal,
  groupedByEvent,
  expandedGroupSet,
  revealedGroups,
  contextualFocus,
  contextualHighlightedRowIds,
  hasQuickFiltersActive,
  complianceGroupBadge,
  quickScheduleFilter,
  quickTypeFilter,
  quickAnimalFilter,
  criticalTargets,
  currentCriticalTarget,
  onNavigateCriticalGroup,
  onToggleGroupExpanded,
  onToggleGroupReveal,
