}

export function EventGroupCard({
  group,
  contextualFocusGroupKey,
  contextualFocusRowId,
  contextualHighlightedRowIds,
  expandedGroupSet,
  revealedGroups,
  hasQuickFiltersActive,
  complianceGroupBadge,
  quickAnimalFilter,
  onEventSummaryBadgeClick,
  onToggleGroupExpanded,
  onToggleGroupReveal,
  onGoToRegistrar,
  onUpdateStatus,
  onNavigateToEvent,
  onNavigateToAnimal,
  renderRowMeta,
  registerRowRef,
}: EventGroupCardProps) {
  const isContextualGroup = contextualFocusGroupKey === group.key;
  const groupStateKey = buildGroupStateKey("evento", group.key);
  const isExpanded = expandedGroupSet.has(groupStateKey);
  const isRevealed = revealedGroups.includes(groupStateKey);
  const displayedRows =
    hasQuickFiltersActive && !isRevealed ? group.visibleRows : group.rows;
  const canToggleReveal =
    hasQuickFiltersActive && group.visibleRows.length < group.rows.length;
  const recommendation = buildAgendaGroupRecommendation(displayedRows);
  const recommendedRow = recommendation
    ? (displayedRows.find((row) => row.item.id === recommendation.rowId) ??
      null)
    : null;
  const compactLayout = buildAgendaBadgeOverflowLayout(
    group.summary.animalBadges,
    3,
  );

  return (
    <Card
      key={group.key}
      className={cn(
        "shadow-none",
        isContextualGroup ? "border-info/25 bg-info-muted/20" : null,
      )}
    >
      <CardHeader className="space-y-3 px-4 pb-2 pt-4 sm:px-5">
        <div className="flex flex-col gap-3 lg:flex-row lg:items-start lg:justify-between">
          <div className="space-y-3">
            <div className="flex flex-wrap items-center gap-2">
              <CardTitle className="text-base">{group.title}</CardTitle>
              <StatusBadge tone="neutral">
                {getGroupVisibilityLabel(
                  group.visibleRows.length,
                  group.rows.length,
                )}
              </StatusBadge>
              {complianceGroupBadge && group.sortMeta.pendingCount > 0 ? (
                <StatusBadge tone={complianceGroupBadge.tone}>
                  {complianceGroupBadge.label}
                </StatusBadge>
              ) : null}
            </div>
            <p className="text-sm text-muted-foreground">{group.subtitle}</p>
            <div className="flex flex-wrap gap-2">
              {group.summary.animalBadges.map((badge, index) => {
                const animalFilter = mapAnimalBadgeToQuickFilter(badge.key);

                if (!animalFilter) {
                  return (
                    <StatusBadge
                      key={badge.key}
                      tone={badge.tone}
                      className={
                        index >= compactLayout.visibleBadges.length
                          ? "hidden sm:inline-flex"
                          : undefined
                      }
                    >
                      {badge.label} {badge.count}
                    </StatusBadge>
                  );
                }

                return (
                  <AgendaQuickFilterBadge
                    key={badge.key}
                    className={
                      index >= compactLayout.visibleBadges.length
                        ? "hidden sm:inline-flex"
                        : undefined
                    }
                    tone={badge.tone}
                    active={quickAnimalFilter === animalFilter}
                    onClick={() =>
                      onEventSummaryBadgeClick(group.key, group.rows, badge.key)
                    }
                  >
                    {badge.label} {badge.count}
                  </AgendaQuickFilterBadge>
                );
              })}
              {compactLayout.hiddenCount > 0 ? (
                <StatusBadge tone="neutral" className="sm:hidden">
                  +{compactLayout.hiddenCount}
                </StatusBadge>
              ) : null}
            </div>
            {recommendation ? (
              <div className="flex flex-wrap items-center gap-2 text-xs sm:text-sm">
                <StatusBadge tone={recommendation.tone}>
                  {recommendation.urgencyLabel}
                </StatusBadge>
                <p className="text-muted-foreground">
                  Proxima acao:{" "}
                  <span className="font-medium text-foreground">
                    {recommendation.actionLabel}
                  </span>{" "}
                  <span className="text-muted-foreground/80">
                    em {recommendation.targetLabel}
                  </span>
                </p>
              </div>
            ) : null}
          </div>
          <AgendaGroupActions
            mode="evento"
            groupKey={group.key}
            groupTitle={group.title}
            isExpanded={isExpanded}
            isRevealed={isRevealed}
            canToggleReveal={canToggleReveal}
            recommendedRow={recommendedRow}
            onGoToRegistrar={onGoToRegistrar}
            onToggleGroupExpanded={onToggleGroupExpanded}
            onToggleGroupReveal={onToggleGroupReveal}
          />
        </div>
      </CardHeader>
      {isExpanded ? (
        <CardContent className="space-y-3">
          {displayedRows.map((row) => (
            <AgendaItemRowCard
              key={row.item.id}
              row={row}
              isContextualMatch={contextualHighlightedRowIds.has(row.item.id)}
              isContextualFocusRow={contextualFocusRowId === row.item.id}
              onGoToRegistrar={onGoToRegistrar}
              onUpdateStatus={onUpdateStatus}
              onNavigateToEvent={onNavigateToEvent}
              onNavigateToAnimal={onNavigateToAnimal}
              renderRowMeta={renderRowMeta}
              registerRowRef={registerRowRef}
            />
          ))}
        </CardContent>
      ) : null}
    </Card>
  );
}

