    "Capim degradado",
    "Outro",
  ],
};

function getForrageiraOptions(tipo: TipoPastoEnum, current: string) {
  const options = FORRAGEIRA_OPTIONS_BY_TIPO[tipo];
  if (!current || options.includes(current)) return options;
  return [current, ...options];
}

