function getDateInDays(data: string | null | undefined, now: Date) {
  if (!data) return null;
  const date = new Date(`${data.slice(0, 10)}T00:00:00`);
  if (Number.isNaN(date.getTime())) return null;
  return Math.max(
    0,
    Math.floor((now.getTime() - date.getTime()) / (1000 * 60 * 60 * 24)),
  );
}

