export function normalizeSanitaryApplicationRoute(
  value: string | null | undefined,
) {
  if (!value) return null;
  const normalized = value
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "_")
    .replace(/^_+|_+$/g, "");

  return ROUTE_ALIASES[normalized] ?? null;
}

