              <p>ID: <span className="text-foreground font-mono">{row.item.id.slice(0, 8)}...</span></p>
              <StatusBadge tone={rowMeta.syncTone} className="h-4 px-1 text-[9px] w-fit">
                {rowMeta.syncLabel}
