            </div>
          </CollapsibleContent>
        </Collapsible>

        {/* A├º├Áes Prim├írias */}
        {isScheduled && (
          <div className="flex flex-col gap-2 pt-1 sm:flex-row">
            <Button 
              size="sm" 
              className="flex-1 font-semibold" 
              onClick={() => onGoToRegistrar(row.item)}
            >
              {registerCtaLabel}
            </Button>
            {canDirectComplete && (
              <Button 
                size="sm" 
                variant="outline" 
                className="flex-1" 
                onClick={() => onUpdateStatus(row.item, "concluido")}
              >
                {directCompleteLabel}
              </Button>
            )}
          </div>
        )}

        {isScheduled && (
          <p className="text-[10px] text-center text-muted-foreground italic">
            {nextStepHint}
          </p>
        )}
      </div>
    </article>
  );
}

